        x3_re = LD(&rio_re[m+6*ios]);
        x3_im = LD(&rio_im[m+6*ios]);
        { const __m512d wr = LD(&W_re[5*me+m]);
          const __m512d wi = LD(&W_im[5*me+m]);
          const __m512d tr = x3_re;
          x3_re = _mm512_fmsub_pd(x3_re,wr,_mm512_mul_pd(x3_im,wi));
          x3_im = _mm512_fmadd_pd(tr,wi,_mm512_mul_pd(x3_im,wr)); }
        x4_re = LD(&rio_re[m+8*ios]);
        x4_im = LD(&rio_im[m+8*ios]);
        { const __m512d wr = LD(&W_re[7*me+m]);
          const __m512d wi = LD(&W_im[7*me+m]);
          const __m512d tr = x4_re;
          x4_re = _mm512_fmsub_pd(x4_re,wr,_mm512_mul_pd(x4_im,wi));
          x4_im = _mm512_fmadd_pd(tr,wi,_mm512_mul_pd(x4_im,wr)); }

        /* radix-5 n2=0 [fwd] */
        {
        __m512d s1r=_mm512_add_pd(x1_re,x4_re), s1i=_mm512_add_pd(x1_im,x4_im);
        __m512d s2r=_mm512_add_pd(x2_re,x3_re), s2i=_mm512_add_pd(x2_im,x3_im);
        __m512d d1r=_mm512_sub_pd(x1_re,x4_re), d1i=_mm512_sub_pd(x1_im,x4_im);
        __m512d d2r=_mm512_sub_pd(x2_re,x3_re), d2i=_mm512_sub_pd(x2_im,x3_im);
        __m512d ss_r=_mm512_add_pd(s1r,s2r), ss_i=_mm512_add_pd(s1i,s2i);
        __m512d t0r=_mm512_fnmadd_pd(cD,ss_r,x0_re), t0i=_mm512_fnmadd_pd(cD,ss_i,x0_im);
        x0_re=_mm512_add_pd(x0_re,ss_r); x0_im=_mm512_add_pd(x0_im,ss_i);
        __m512d p1r=_mm512_fmadd_pd(cA,_mm512_sub_pd(s1r,s2r),t0r), p1i=_mm512_fmadd_pd(cA,_mm512_sub_pd(s1i,s2i),t0i);
        __m512d p2r=_mm512_fnmadd_pd(cA,_mm512_sub_pd(s1r,s2r),t0r), p2i=_mm512_fnmadd_pd(cA,_mm512_sub_pd(s1i,s2i),t0i);
        __m512d qar=_mm512_fmadd_pd(cC,d2i,_mm512_mul_pd(cB,d1i)), qai=_mm512_fmadd_pd(cC,d2r,_mm512_mul_pd(cB,d1r));
        __m512d qbr=_mm512_fmsub_pd(cB,d2i,_mm512_mul_pd(cC,d1i)), qbi=_mm512_fmsub_pd(cB,d2r,_mm512_mul_pd(cC,d1r));
        x1_re=_mm512_add_pd(p1r,qar); x1_im=_mm512_sub_pd(p1i,qai);
        x4_re=_mm512_sub_pd(p1r,qar); x4_im=_mm512_add_pd(p1i,qai);
        x2_re=_mm512_sub_pd(p2r,qbr); x2_im=_mm512_add_pd(p2i,qbi);
        x3_re=_mm512_add_pd(p2r,qbr); x3_im=_mm512_sub_pd(p2i,qbi);
        }

        _mm512_store_pd(&spill_re[0*8], x0_re);
        _mm512_store_pd(&spill_im[0*8], x0_im);
        _mm512_store_pd(&spill_re[1*8], x1_re);
        _mm512_store_pd(&spill_im[1*8], x1_im);
        _mm512_store_pd(&spill_re[2*8], x2_re);
        _mm512_store_pd(&spill_im[2*8], x2_im);
        _mm512_store_pd(&spill_re[3*8], x3_re);
        _mm512_store_pd(&spill_im[3*8], x3_im);
        _mm512_store_pd(&spill_re[4*8], x4_re);
        _mm512_store_pd(&spill_im[4*8], x4_im);

        /* sub-FFT n2=1 */
        x0_re = LD(&rio_re[m+1*ios]);
        x0_im = LD(&rio_im[m+1*ios]);
        { const __m512d wr = LD(&W_re[0*me+m]);
          const __m512d wi = LD(&W_im[0*me+m]);
          const __m512d tr = x0_re;
          x0_re = _mm512_fmsub_pd(x0_re,wr,_mm512_mul_pd(x0_im,wi));
          x0_im = _mm512_fmadd_pd(tr,wi,_mm512_mul_pd(x0_im,wr)); }
        x1_re = LD(&rio_re[m+3*ios]);
        x1_im = LD(&rio_im[m+3*ios]);
        { const __m512d wr = LD(&W_re[2*me+m]);
          const __m512d wi = LD(&W_im[2*me+m]);
          const __m512d tr = x1_re;
          x1_re = _mm512_fmsub_pd(x1_re,wr,_mm512_mul_pd(x1_im,wi));
          x1_im = _mm512_fmadd_pd(tr,wi,_mm512_mul_pd(x1_im,wr)); }
        x2_re = LD(&rio_re[m+5*ios]);
        x2_im = LD(&rio_im[m+5*ios]);
        { const __m512d wr = LD(&W_re[4*me+m]);
          const __m512d wi = LD(&W_im[4*me+m]);
          const __m512d tr = x2_re;
          x2_re = _mm512_fmsub_pd(x2_re,wr,_mm512_mul_pd(x2_im,wi));
          x2_im = _mm512_fmadd_pd(tr,wi,_mm512_mul_pd(x2_im,wr)); }
        x3_re = LD(&rio_re[m+7*ios]);
        x3_im = LD(&rio_im[m+7*ios]);
        { const __m512d wr = LD(&W_re[6*me+m]);
          const __m512d wi = LD(&W_im[6*me+m]);
          const __m512d tr = x3_re;
          x3_re = _mm512_fmsub_pd(x3_re,wr,_mm512_mul_pd(x3_im,wi));
          x3_im = _mm512_fmadd_pd(tr,wi,_mm512_mul_pd(x3_im,wr)); }
        x4_re = LD(&rio_re[m+9*ios]);
        x4_im = LD(&rio_im[m+9*ios]);
        { const __m512d wr = LD(&W_re[8*me+m]);
          const __m512d wi = LD(&W_im[8*me+m]);
          const __m512d tr = x4_re;
          x4_re = _mm512_fmsub_pd(x4_re,wr,_mm512_mul_pd(x4_im,wi));
          x4_im = _mm512_fmadd_pd(tr,wi,_mm512_mul_pd(x4_im,wr)); }

        /* radix-5 n2=1 [fwd] */
        {
        __m512d s1r=_mm512_add_pd(x1_re,x4_re), s1i=_mm512_add_pd(x1_im,x4_im);
        __m512d s2r=_mm512_add_pd(x2_re,x3_re), s2i=_mm512_add_pd(x2_im,x3_im);
        __m512d d1r=_mm512_sub_pd(x1_re,x4_re), d1i=_mm512_sub_pd(x1_im,x4_im);
        __m512d d2r=_mm512_sub_pd(x2_re,x3_re), d2i=_mm512_sub_pd(x2_im,x3_im);
        __m512d ss_r=_mm512_add_pd(s1r,s2r), ss_i=_mm512_add_pd(s1i,s2i);
        __m512d t0r=_mm512_fnmadd_pd(cD,ss_r,x0_re), t0i=_mm512_fnmadd_pd(cD,ss_i,x0_im);
        x0_re=_mm512_add_pd(x0_re,ss_r); x0_im=_mm512_add_pd(x0_im,ss_i);
        __m512d p1r=_mm512_fmadd_pd(cA,_mm512_sub_pd(s1r,s2r),t0r), p1i=_mm512_fmadd_pd(cA,_mm512_sub_pd(s1i,s2i),t0i);
        __m512d p2r=_mm512_fnmadd_pd(cA,_mm512_sub_pd(s1r,s2r),t0r), p2i=_mm512_fnmadd_pd(cA,_mm512_sub_pd(s1i,s2i),t0i);
        __m512d qar=_mm512_fmadd_pd(cC,d2i,_mm512_mul_pd(cB,d1i)), qai=_mm512_fmadd_pd(cC,d2r,_mm512_mul_pd(cB,d1r));
        __m512d qbr=_mm512_fmsub_pd(cB,d2i,_mm512_mul_pd(cC,d1i)), qbi=_mm512_fmsub_pd(cB,d2r,_mm512_mul_pd(cC,d1r));
        x1_re=_mm512_add_pd(p1r,qar); x1_im=_mm512_sub_pd(p1i,qai);
        x4_re=_mm512_sub_pd(p1r,qar); x4_im=_mm512_add_pd(p1i,qai);
        x2_re=_mm512_sub_pd(p2r,qbr); x2_im=_mm512_add_pd(p2i,qbi);
        x3_re=_mm512_add_pd(p2r,qbr); x3_im=_mm512_sub_pd(p2i,qbi);
        }

        _mm512_store_pd(&spill_re[5*8], x0_re);
        _mm512_store_pd(&spill_im[5*8], x0_im);
        _mm512_store_pd(&spill_re[6*8], x1_re);
        _mm512_store_pd(&spill_im[6*8], x1_im);
        _mm512_store_pd(&spill_re[7*8], x2_re);
        _mm512_store_pd(&spill_im[7*8], x2_im);
        _mm512_store_pd(&spill_re[8*8], x3_re);
        _mm512_store_pd(&spill_im[8*8], x3_im);
        _mm512_store_pd(&spill_re[9*8], x4_re);
        _mm512_store_pd(&spill_im[9*8], x4_im);

        /* PASS 2: 5x radix-2 columns */

        /* column k1=0 */
        x0_re = _mm512_load_pd(&spill_re[0*8]);
        x0_im = _mm512_load_pd(&spill_im[0*8]);
        x1_re = _mm512_load_pd(&spill_re[5*8]);
        x1_im = _mm512_load_pd(&spill_im[5*8]);

        /* radix-2 k1=0 [fwd] */
