        ST(&rio_re[m+3*ios], x0_re);
        ST(&rio_im[m+3*ios], x0_im);
        ST(&rio_re[m+8*ios], x1_re);
        ST(&rio_im[m+8*ios], x1_im);

        /* column k1=4 */
