    const __m512d cC = _mm512_set1_pd(0.587785252292473137103456792829092592000961304);
    const __m512d cD = _mm512_set1_pd(0.250000000000000000000000000000000000000000000);
    (void)sign_flip;

    __attribute__((aligned(64))) double spill_re[80];
    __attribute__((aligned(64))) double spill_im[80];

